import { useState } from "react";
import { motion } from "framer-motion";
import { Plus, Trash2, ChevronDown, ChevronUp } from "lucide-react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


function getLetterGrade(pct: number) {
  if (pct >= 97) return "A+"; if (pct >= 93) return "A"; if (pct >= 90) return "A-";
  if (pct >= 87) return "B+"; if (pct >= 83) return "B"; if (pct >= 80) return "B-";
  if (pct >= 77) return "C+"; if (pct >= 73) return "C"; if (pct >= 70) return "C-";
  if (pct >= 67) return "D+"; if (pct >= 63) return "D"; if (pct >= 60) return "D-";
  return "F";
}

const FAQS = [
  { q: "How is a weighted average grade calculated?", a: "Multiply each assignment score by its weight percentage, sum all weighted scores, then divide by the total weight. For example: Exam 1 (80%)  x  40 weight + Homework (90%)  x  20 weight = 32 + 18 = 50 weighted points out of 60 total weight = 83.3%." },
  { q: "What is a passing grade?", a: "Most educational institutions consider 60% or D as the minimum passing grade. However, many programs require a C (70%) or higher for credit. Graduate programs often require a B (80%) or higher." },
  { q: "How do I calculate what I need on the final exam?", a: "Use the formula: Required Final Score = (Desired Grade - Current Grade  x  Current Weight%) / Final Weight%. For example, if you have 78% with 75% of the course complete and need a 80% final grade, you need: (80 - 78  x  0.75) / 0.25 = 86%." },
  { q: "What is the difference between weighted and unweighted grades?", a: "Unweighted grades treat all assignments equally. Weighted grades assign different importance to different assessments - a final exam worth 40% has more impact on your grade than a quiz worth 5%." },
  { q: "What does it mean if my total weight is not 100%?", a: "If your total weight exceeds 100%, some assignments may have extra credit opportunities or you've entered incorrect weights. If it's below 100%, there are remaining assignments not yet entered. For the most accurate grade prediction, ensure weights add to 100%." },
  { q: "How do I calculate my current grade mid-semester?", a: "Enter only the assignments you've received grades for with their respective weights. Divide your weighted score total by the total weight of graded assignments (not 100%). This gives your current grade based on completed work." },
  { q: "What GPA does an 85% correspond to?", a: "An 85% falls in the B range, corresponding to approximately 3.0 on the 4.0 GPA scale. An 87-89% is B+ (3.3 GPA), 83-86% is B (3.0 GPA), and 80-82% is B- (2.7 GPA)." },
];

export default function GradeCalculator() {
  const [assignments, setAssignments] = useState([
    { name: "Homework", score: 88, weight: 20 },
    { name: "Midterm", score: 75, weight: 30 },
    { name: "Final Exam", score: 82, weight: 40 },
    { name: "Participation", score: 95, weight: 10 },
  ]);

  const totalWeight = assignments.reduce((sum, a) => sum + a.weight, 0);
  const weightedSum = assignments.reduce((sum, a) => sum + a.score * a.weight, 0);
  const avgGrade = totalWeight > 0 ? weightedSum / totalWeight : 0;
  const letterGrade = getLetterGrade(avgGrade);
  const gradients: Record<string, string> = { "A+": "from-emerald-500 to-emerald-700", A: "from-emerald-500 to-emerald-700", "A-": "from-teal-500 to-teal-700", "B+": "from-sky-500 to-sky-700", B: "from-sky-500 to-sky-700", "B-": "from-blue-500 to-blue-700", "C+": "from-amber-500 to-amber-700", C: "from-amber-500 to-amber-700", "C-": "from-orange-500 to-orange-700" };
  const gradient = gradients[letterGrade] ?? "from-red-500 to-red-700";

  const addAssignment = () => setAssignments([...assignments, { name: `Assignment ${assignments.length + 1}`, score: 80, weight: 10 }]);
  const remove = (i: number) => setAssignments(assignments.filter((_, idx) => idx !== i));
  const update = (i: number, field: "name" | "score" | "weight", value: string | number) => setAssignments(assignments.map((a, idx) => idx === i ? { ...a, [field]: value } : a));

  return (
    <>
      <SEOHead
        title="Free Grade Calculator Online - Calculate Your Weighted Course Grade Instantly | CalcHive"
        description="Free online grade calculator. Calculate your weighted course grade from assignments, exams and their weights instantly. 100% free for all students, no signup required."
        canonical="/grade-calculator"
        keywords="free grade calculator, weighted grade calculator free online, course grade calculator free, calculate final grade free, free student grade calculator"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Grade Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free grade calculator to calculate final grade free from assignments, exams, scores, and weights. This weighted grade calculator free online also works as a course grade calculator free and free student grade calculator.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-3 mb-6">
            <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-muted-foreground px-1">
              <span className="col-span-5">Assignment</span>
              <span className="col-span-3 text-center">Score (%)</span>
              <span className="col-span-3 text-center">Weight (%)</span>
              <span className="col-span-1" />
            </div>
            {assignments.map((a, i) => (
              <div key={i} className="grid grid-cols-12 gap-2 items-center">
                <input value={a.name} onChange={e => update(i, "name", e.target.value)} className="col-span-5 px-3 py-2 rounded-lg border border-input bg-background text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40" />
                <input type="number" value={a.score} min={0} max={100} onChange={e => update(i, "score", Number(e.target.value))} className="col-span-3 px-2 py-2 rounded-lg border border-input bg-background text-sm text-center text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40" />
                <input type="number" value={a.weight} min={0} max={100} onChange={e => update(i, "weight", Number(e.target.value))} className="col-span-3 px-2 py-2 rounded-lg border border-input bg-background text-sm text-center text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40" />
                <button onClick={() => remove(i)} className="col-span-1 p-1 text-muted-foreground hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
              </div>
            ))}
          </div>
          <div className="flex items-center justify-between mb-8">
            <button onClick={addAssignment} className="flex items-center gap-2 text-sm font-semibold text-primary hover:bg-accent px-3 py-1.5 rounded-lg transition-colors">
              <Plus className="w-4 h-4" /> Add Assignment
            </button>
            <span className={`text-xs font-medium ${totalWeight === 100 ? "text-emerald-600" : "text-amber-600"}`}>Total weight: {totalWeight}%</span>
          </div>
          <motion.div key={JSON.stringify(assignments)} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`bg-gradient-to-br ${gradient} rounded-2xl p-6 text-center shadow-lg`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Current Grade</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-grade">{avgGrade.toFixed(1)}%</p>
              <p className="text-white/70 text-sm mt-1">Letter Grade: {letterGrade}</p>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Weighted Grade for Free</h2>
          <p className="text-muted-foreground leading-relaxed">A weighted grade gives more importance to some assignments than others. Rather than averaging scores directly, each score is multiplied by its weight. The sum of weighted scores is divided by the total weight - giving a more accurate measure of performance in weighted courses.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Weighted Score = BP (Score  x  Weight)</p>
            <p>Grade % = Weighted Score  x  Total Weight</p>
            <p className="text-xs text-muted-foreground mt-2">Example: 88% x 20 + 75% x 30 + 82% x 40 + 95% x 10 = 8,240  x  100 = 82.4%</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How Assignment and Exam Weights Affect Your Final Grade</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Letter Grade", "Percentage", "GPA", "Description"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["A+", "97-100%", "4.0", "Outstanding"],
                  ["A", "93-96%", "4.0", "Excellent"],
                  ["A-", "90-92%", "3.7", "Excellent"],
                  ["B+", "87-89%", "3.3", "Above Average"],
                  ["B", "83-86%", "3.0", "Good"],
                  ["B-", "80-82%", "2.7", "Good"],
                  ["C+", "77-79%", "2.3", "Average"],
                  ["C", "73-76%", "2.0", "Average / Satisfactory"],
                  ["C-", "70-72%", "1.7", "Below Average"],
                  ["D", "60-69%", "1.0", "Passing (minimum)"],
                  ["F", "0-59%", "0.0", "Failing"],
                ].map(([grade, pct, gpa, desc]) => (
                  <tr key={grade} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{grade}</td>
                    <td className="py-2.5 px-4 text-amber-600 dark:text-amber-400 font-medium">{pct}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{gpa}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{desc}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Course Grade Tool for Every Student</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free tool on any device to solve the calculation instantly, check your work, and get a clear result without downloads or signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/grade-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


